/**
 * Ancestry Feats Seed Data
 *
 * 13 effective lists (10 races + Drow subrace + Aasimar 3 paths) × 5 tiers
 * × 3 choices = 195 feats. Sourced from ANCESTRY_FEATS.md.
 *
 * list_id uses: dwarf, elf, drow, human, halfling, dragonborn, half_elf,
 *   half_orc, tiefling, aasimar_protector, aasimar_scourge, aasimar_fallen,
 *   warforged.
 *
 * Tiers: 1, 3, 7, 13, 18. Each tier offers 3 feat choices; player picks 1.
 *
 * Description style: full sentences, second person, integrated clauses
 * (no fragment lists or parenthesized rate notes). `choices` array on a
 * feat declares any player sub-choice required at selection time (skill
 * proficiency, language, damage type, etc.) so the UI can render a picker.
 */

export const ANCESTRY_FEATS = [
  // ============ DWARF ============
  { list_id: 'dwarf', tier: 1, choice_index: 1, feat_name: 'Stout-Hearted', description: 'Your maximum hit points increase by 2, and you gain 1 additional hit point for each character level you have (applied retroactively). If you are a Hill Dwarf, this stacks with your subrace bonus.', mechanics: '+2 HP base + 1/level retroactive', flavor: 'A dwarf is built to endure.' },
  { list_id: 'dwarf', tier: 1, choice_index: 2, feat_name: "Clan's Craft", description: 'You gain proficiency with one additional artisan tool of your choice. After one minute of examining any dwarven-crafted item, you automatically identify its maker, originating clan, and approximate age.', mechanics: '+1 tool prof; passive dwarven-craft identification', flavor: 'You were taught at a clan hearth.', choices: [{ id: 'tool', type: 'tool', count: 1, label: 'Choose an artisan tool', options: 'any_artisan_tool' }] },
  { list_id: 'dwarf', tier: 1, choice_index: 3, feat_name: 'Grudge-Sworn', description: 'Choose one traditional dwarven foe: giants, orcs, drow, or goblinoids. You gain advantage on initiative rolls when at least one creature of that type is present, and you know basic tactical lore about them.', mechanics: 'Chosen-foe initiative advantage + tactical lore', flavor: "Your clan's grudge songs name this enemy.", choices: [{ id: 'foe', type: 'enemy_type', count: 1, label: 'Choose a traditional foe', options: ['giants', 'orcs', 'drow', 'goblinoids'] }] },
  { list_id: 'dwarf', tier: 3, choice_index: 1, feat_name: 'Rock Runner', description: 'Difficult terrain made of rubble, rocks, or uneven stone does not cost you extra movement. You also gain advantage on Dexterity (Acrobatics) and Strength (Athletics) checks to stay upright on unstable rocky surfaces.', mechanics: 'Ignore rocky difficult terrain; footing advantage', flavor: 'The stone knows your weight.' },
  { list_id: 'dwarf', tier: 3, choice_index: 2, feat_name: 'Underfoot', description: 'While within 30 feet of natural stone, you gain tremorsense out to 10 feet through that stone, letting you sense vibrations and approaching creatures.', mechanics: 'Passive 10-ft stone tremorsense (in natural-stone environments)', flavor: 'You listen to stone.' },
  { list_id: 'dwarf', tier: 3, choice_index: 3, feat_name: 'Unburdened Iron', description: 'Heavy armor no longer reduces your movement speed. If your Strength does not meet the normal requirement for a heavy armor, you may ignore that requirement, though you still do not gain proficiency in armor you are not trained in.', mechanics: 'No heavy armor speed penalty; STR requirement waived', flavor: 'Dwarves were not made to be slowed by mere metal.' },
  { list_id: 'dwarf', tier: 7, choice_index: 1, feat_name: 'Boulder Push', description: 'Once per short rest, when you succeed on a Strength check to grapple, shove, or push a creature, you can launch the target up to 10 feet in a chosen direction. If the target collides with a wall or another creature, both take 1d6 bludgeoning damage and must succeed on a DC 13 Strength save or fall prone.', mechanics: '1/SR shove + 10 ft push + collision damage', flavor: 'You do not push. You hurl.' },
  { list_id: 'dwarf', tier: 7, choice_index: 2, feat_name: 'Stonecunning Adept', description: 'By touching a stone surface, you can identify traps, structural weaknesses, secret doors, and recent construction. You gain advantage on Intelligence (Investigation) checks made against worked stone.', mechanics: 'Touch-based stone analysis; Investigation advantage on stone', flavor: 'The stone whispers.' },
  { list_id: 'dwarf', tier: 7, choice_index: 3, feat_name: 'Anvil Steady', description: 'You are immune to being knocked prone by creatures of Medium size or smaller, and you gain advantage on saves to resist being knocked prone by Large or larger creatures and forces.', mechanics: 'Prone immunity vs Medium-; advantage vs Large+', flavor: 'The line begins at your boots.' },
  { list_id: 'dwarf', tier: 13, choice_index: 1, feat_name: 'Deep Sight', description: 'Your darkvision extends to 120 feet, and you can see normally in magical darkness up to 30 feet.', mechanics: 'Darkvision 120 ft + 30-ft magical darkness sight', flavor: 'Tested by the dark beneath the dark.' },
  { list_id: 'dwarf', tier: 13, choice_index: 2, feat_name: 'Stoneshaping (Minor)', description: 'Once per long rest, you can shape unworked stone as if it were clay for up to 10 minutes. Over that time, you may alter a total of 5 cubic feet of stone — opening passages up to 3 feet on a side, reshaping floors, or carving patterns. Changes are permanent unless reshaped again.', mechanics: '1/LR 10-min stone shaping (5 cubic ft cap)', flavor: 'Your hands remember what stone once was.' },
  { list_id: 'dwarf', tier: 13, choice_index: 3, feat_name: "Mountain's Stoutness", description: 'Choose one damage type tied to a traditional dwarven foe — fire (Muspelheim giants), cold (ice giants), necrotic (drow), or psychic (aboleth deeps). You gain resistance to that damage type.', mechanics: 'Chosen damage resistance (fire/cold/necrotic/psychic)', flavor: 'The old war scar still shields you.', choices: [{ id: 'damage_type', type: 'damage_type', count: 1, label: 'Choose a damage resistance', options: ['fire', 'cold', 'necrotic', 'psychic'] }] },
  { list_id: 'dwarf', tier: 18, choice_index: 1, feat_name: 'Walk in Stone', description: 'Once per long rest, you can take an action to merge with a stone wall, floor, or ceiling and travel through stone at half your walking speed for up to 10 minutes. While merged, you can see and hear through up to 1 foot of stone but cannot attack or cast spells. You emerge at any chosen point within your traveled range.', mechanics: '1/LR 10-min stone walking', flavor: 'The stone took you in.' },
  { list_id: 'dwarf', tier: 18, choice_index: 2, feat_name: "Moradin's Favor", description: 'Once per long rest, when you use artisan tools to craft or repair an item, you make the check with advantage and treat any 1 rolled on the dice as the die maximum instead. The finished item gains minor magical resonance, the nature of which the DM determines.', mechanics: '1/LR crafting advantage + max-on-1s + minor resonance', flavor: 'The Dwarffather smiles on good work.' },
  { list_id: 'dwarf', tier: 18, choice_index: 3, feat_name: 'Unbreakable', description: 'You are immune to being petrified. Once per long rest, when you are reduced to 0 hit points, you instead drop to half your hit point maximum and become immune to being knocked prone for 1 minute.', mechanics: 'Petrify immunity; 1/LR drop-to-half-HP + 1-min prone immunity', flavor: 'Stone that remembers being flesh.' },

  // ============ ELF ============
  { list_id: 'elf', tier: 1, choice_index: 1, feat_name: 'Elven Grace', description: 'You gain proficiency in one Dexterity-based skill of your choice from Acrobatics, Stealth, or Sleight of Hand. Once per short rest, when you fail a Dexterity check or save, you may reroll with advantage and must use the new result.', mechanics: '+1 DEX skill prof; 1/SR DEX reroll with advantage', flavor: 'Light as the old songs describe.', choices: [{ id: 'skill', type: 'skill', count: 1, label: 'Choose a Dexterity skill', options: ['Acrobatics', 'Stealth', 'Sleight of Hand'] }] },
  { list_id: 'elf', tier: 1, choice_index: 2, feat_name: 'Weave-Touched', description: 'You learn one cantrip of your choice from the wizard or druid spell list. When you take this feat, choose Intelligence or Wisdom as your spellcasting ability for this cantrip. This cantrip is in addition to any cantrip granted by the High Elf subrace.', mechanics: '+1 cantrip (wizard or druid list, INT or WIS ability)', flavor: 'The Weave is close to elvenkind.', choices: [{ id: 'cantrip', type: 'cantrip', count: 1, label: 'Choose a cantrip (wizard or druid list)', options: 'any_cantrip_wizard_or_druid' }, { id: 'ability', type: 'ability_score', count: 1, label: 'Spellcasting ability for this cantrip', options: ['INT', 'WIS'] }] },
  { list_id: 'elf', tier: 1, choice_index: 3, feat_name: 'Eyes of the Forest', description: 'In natural environments, your proficiency bonus is doubled for Wisdom (Perception) checks made to notice creatures, tracks, or unusual signs. You can also see twice as far as a normal human in daylight.', mechanics: 'Double proficiency in wilderness Perception; 2× daylight vision', flavor: 'Your people have watched the forests longer than mountains have stood.' },
  { list_id: 'elf', tier: 3, choice_index: 1, feat_name: 'Light Step', description: 'You may move across difficult terrain composed of vegetation, snow, or still water without spending extra movement. When you move at half speed on natural surfaces, you leave no tracks and make no sound.', mechanics: 'Natural difficult terrain immunity; silent trackless half-speed movement', flavor: 'The earth rarely remembers elves.' },
  { list_id: 'elf', tier: 3, choice_index: 2, feat_name: 'Fey Reflexes', description: 'You gain advantage on Wisdom saving throws made to resist being charmed, frightened, compelled, or magically read. You also sense the presence of any fey creature within 60 feet of you.', mechanics: 'WIS save advantage vs charm/fright/compel/mind-read; 60-ft fey sense', flavor: 'The Feywild left a thread in you.' },
  { list_id: 'elf', tier: 3, choice_index: 3, feat_name: 'Trance Mastery', description: 'Your trance requires only 2 hours instead of 4 to gain the benefits of a long rest. While in trance, you remain aware of your surroundings and cannot be surprised by approaching creatures.', mechanics: '2-hour trance; trance-time surprise immunity', flavor: 'You refined reverie past resting.' },
  { list_id: 'elf', tier: 7, choice_index: 1, feat_name: 'Arcane Inheritance', description: 'Once per long rest, you can cast one 1st-level utility spell from the wizard spell list without expending a spell slot. Choose the spell when you take this feat from the following options: Comprehend Languages, Detect Magic, Disguise Self, Feather Fall, or Unseen Servant.', mechanics: '1/LR free 1st-level wizard utility spell', flavor: 'Old magic lives in the blood of your line.', choices: [{ id: 'spell', type: 'spell', count: 1, label: 'Choose a utility spell', options: ['Comprehend Languages', 'Detect Magic', 'Disguise Self', 'Feather Fall', 'Unseen Servant'] }] },
  { list_id: 'elf', tier: 7, choice_index: 2, feat_name: "Huntmaster's Gift", description: 'You gain advantage on attack rolls against any creature that has not yet taken a turn in the current combat. Your first attack of any combat deals an additional 1d6 damage of the weapon\'s type.', mechanics: 'Advantage vs creatures without turn taken; +1d6 on first attack', flavor: 'Strike first, strike true.' },
  { list_id: 'elf', tier: 7, choice_index: 3, feat_name: 'Twilight Walker', description: 'You see normally in dim light as though it were bright. At dusk, at dawn, or in dim light, you gain advantage on Stealth checks and your attacks deal an additional 1d4 damage against any enemy that has not seen you.', mechanics: 'Dim-light sight; dim-light Stealth advantage + 1d4 stealth damage', flavor: 'The half-light is your element.' },
  { list_id: 'elf', tier: 13, choice_index: 1, feat_name: 'Fey Step', description: 'Once per short rest, you can teleport up to 30 feet to an unoccupied space you can see. This teleport requires no components — only a flicker of fey inheritance.', mechanics: '1/SR 30-ft teleport', flavor: 'The world hesitates, and you slip through.' },
  { list_id: 'elf', tier: 13, choice_index: 2, feat_name: 'Master of the Weave', description: 'You learn two additional cantrips from a single spell list of your choice (wizard, druid, bard, or cleric). One of these cantrips may be a combat cantrip. Choose Intelligence or Wisdom as the spellcasting ability for both.', mechanics: '+2 cantrips (any single list, INT or WIS); one combat cantrip allowed', flavor: 'The hum has become a language.', choices: [{ id: 'list', type: 'spell_list', count: 1, label: 'Choose a spell list', options: ['wizard', 'druid', 'bard', 'cleric'] }, { id: 'ability', type: 'ability_score', count: 1, label: 'Spellcasting ability', options: ['INT', 'WIS'] }] },
  { list_id: 'elf', tier: 13, choice_index: 3, feat_name: 'Elvensight', description: 'Your darkvision extends to 120 feet, and you can see through magical darkness up to 30 feet. You are immune to being magically blinded, though mundane blinding effects still affect you for 1 round.', mechanics: 'Darkvision 120 ft; 30-ft magical dark sight; magical blind immunity', flavor: 'Your eyes remember a time before torches.' },
  { list_id: 'elf', tier: 18, choice_index: 1, feat_name: 'Ageless Grace', description: 'You are immune to aging from both natural and magical sources. Once per long rest, when you would fail a death saving throw, you succeed instead.', mechanics: 'Aging immunity; 1/LR death save reversal', flavor: 'Time is a current you stand in, unmoved.' },
  { list_id: 'elf', tier: 18, choice_index: 2, feat_name: 'Walker Between Worlds', description: 'Once per long rest, you can take an action to step briefly into the Feywild and back, becoming invisible and able to pass through non-magical barriers such as walls, doors, and thickets for up to 10 minutes. You cannot attack or cast offensive spells during this time, and doing so immediately ends the effect.', mechanics: '1/LR 10-min Feywild phasing (invisible + barrier pass; non-combat only)', flavor: 'The space between worlds is a shorter step for your kind.' },
  { list_id: 'elf', tier: 18, choice_index: 3, feat_name: 'Voice of the Weave', description: 'Once per long rest, you can cast one spell of 5th level or lower from the wizard or druid spell list without expending a spell slot or material components. Choose this spell when you take this feat — it cannot be changed. Your spellcasting ability for this spell is Intelligence or Wisdom (chosen at feat time).', mechanics: '1/LR free 5th-or-lower spell (wizard or druid; fixed at feat time)', flavor: 'You ask the Weave for favors. Sometimes it listens.', choices: [{ id: 'spell', type: 'spell_freeform', count: 1, label: 'Spell (5th-level or lower, wizard or druid list)', options: 'any_spell_level_5_or_lower_wizard_or_druid' }, { id: 'ability', type: 'ability_score', count: 1, label: 'Spellcasting ability', options: ['INT', 'WIS'] }] },

  // ============ DROW ============
  { list_id: 'drow', tier: 1, choice_index: 1, feat_name: "Lolth's Scion", description: 'You gain resistance to poison damage and advantage on saves against being poisoned. By concentrating for 1 minute, you can detect poison in any food, drink, or surface within 10 feet of you.', mechanics: 'Poison resistance + save advantage; 10-ft poison detection', flavor: "The Spider Queen's blood runs in you." },
  { list_id: 'drow', tier: 1, choice_index: 2, feat_name: 'Shadowbred', description: 'You gain proficiency in the Stealth skill. Once per short rest, you may reroll a failed Stealth check with advantage and must use the new roll. You can also speak at any audible volume while producing no more sound than a whisper.', mechanics: 'Stealth prof; 1/SR Stealth reroll with advantage; whisper-loud speech', flavor: 'You learned quiet before language.' },
  { list_id: 'drow', tier: 1, choice_index: 3, feat_name: "Weaver's Tongue", description: 'You learn Undercommon and one additional language of your choice from Drow Sign Language, Underdark thieves\' cant, or an ancient elven dialect. You gain advantage on Charisma (Deception) checks made in any of these Underdark languages.', mechanics: 'Undercommon + 1 Underdark language; Deception advantage in Underdark tongues', flavor: 'The web has many strands.', choices: [{ id: 'language', type: 'language', count: 1, label: 'Choose an additional Underdark language', options: ['Drow Sign Language', "Underdark thieves' cant", 'Ancient Elven Dialect'] }] },
  { list_id: 'drow', tier: 3, choice_index: 1, feat_name: "Spider's Grace", description: 'You have a climbing speed equal to your walking speed on stone, cave, or other unworked natural surfaces. If you have a free hand and are in dim light or darkness, you can climb on ceilings.', mechanics: 'Climbing speed = walk on natural stone; ceiling climb in dim/dark', flavor: "Lolth's children do not fear walls." },
  { list_id: 'drow', tier: 3, choice_index: 2, feat_name: 'Drow Magic Expanded', description: 'In addition to your standard Drow spell progression, you can cast Faerie Fire once per long rest and Detect Magic once per long rest, each without expending a spell slot. Charisma is your spellcasting ability for these spells.', mechanics: '+1/LR Faerie Fire and +1/LR Detect Magic (CHA)', flavor: 'The Underdark taught your line to see in the dark.' },
  { list_id: 'drow', tier: 3, choice_index: 3, feat_name: 'Keen Instinct', description: 'You gain advantage on Wisdom (Insight) checks made to detect lies, treachery, or hidden motives.', mechanics: 'Insight advantage vs deception/treachery', flavor: 'Honesty is a luxury you were not given.' },
  { list_id: 'drow', tier: 7, choice_index: 1, feat_name: 'Shadow Step', description: 'Once per short rest, while you are in dim light or darkness, you can teleport up to 60 feet to another area of dim light or darkness that you can see. You are invisible until the start of your next turn.', mechanics: '1/SR 60-ft dim/dark teleport with 1-round invisibility', flavor: 'The darkness is yours.' },
  { list_id: 'drow', tier: 7, choice_index: 2, feat_name: 'Venomous Strike', description: 'Once per long rest, as a bonus action, you coat a weapon with drow poison. For the next minute, your next three successful attacks with that weapon each deal an additional 2d4 poison damage. On the first hit, the target must succeed on a Constitution save (DC 8 + your proficiency bonus + your Dexterity modifier) or be poisoned for 1 minute.', mechanics: '1/LR 1-min poison coating (3 hits +2d4, poisoned on first)', flavor: 'Your body remembers the old preparations.' },
  { list_id: 'drow', tier: 7, choice_index: 3, feat_name: 'Dark Sight', description: 'Your Superior Darkvision extends to 240 feet, and you can see normally in dim light and in magical darkness within 60 feet. Your Sunlight Sensitivity worsens, however — you now have disadvantage on attack rolls AND on all ability checks made in direct sunlight.', mechanics: 'Darkvision 240 ft + 60-ft magical dark sight; Sunlight Sensitivity worsens to all checks', flavor: 'The deep welcomes you more each year.' },
  { list_id: 'drow', tier: 13, choice_index: 1, feat_name: "Lolth's Favor", description: 'Once per long rest, you can summon a Medium spider (use the giant wolf spider statistics from the Monster Manual) for 1 minute. It understands Common and the spider-kin tongue. The spider is kin rather than a thrall — it may help, observe, or refuse based on your standing with Lolth. The DM tracks this standing: devout followers receive loyalty; apostates receive unreliability.', mechanics: '1/LR summon giant wolf spider (loyalty varies by Lolth standing)', flavor: 'The web reaches you. Whether it obeys is another matter.' },
  { list_id: 'drow', tier: 13, choice_index: 2, feat_name: 'Drowcraft Weapon', description: 'You bond with a chosen weapon, transforming it into a drowcraft weapon with +1 to attack and damage rolls and dealing an additional 1d4 poison damage. Only you may wield it, and it crumbles to dust if exposed to direct sunlight for 1 hour. You can replace a destroyed drowcraft weapon via a 7-day dark ritual.', mechanics: '+1 magical weapon with 1d4 poison; sunlight-fragile', flavor: 'Some weapons only remember their edge in the right hand.' },
  { list_id: 'drow', tier: 13, choice_index: 3, feat_name: 'House Heritage', description: 'You know Drow noble sign language and the sigils of major houses. You gain advantage on Persuasion, Deception, and Intimidation checks against Drow and Underdark creatures who recognize your bearing. Members of your former house recognize you on sight — and may not be kindly disposed.', mechanics: 'Advantage on social checks with Drow/Underdark; former house recognition risk', flavor: 'The house is always part of you.' },
  { list_id: 'drow', tier: 18, choice_index: 1, feat_name: "Spider Queen's Disciple", description: 'While in darkness, you gain blindsight out to 60 feet by perceiving the web of fate as vibrations. This blindsight functions even when you are blinded or silenced.', mechanics: 'Darkness blindsight 60 ft', flavor: 'The web hums. You hear it whether you wish to or not.' },
  { list_id: 'drow', tier: 18, choice_index: 2, feat_name: 'Darkness Embodied', description: 'You gain resistance to radiant damage. Once per long rest, as an action, you wrap yourself in a 10-foot-radius sphere of magical darkness for 1 minute. Only you can see through it, and the darkness moves with you.', mechanics: 'Radiant resistance; 1/LR 10-ft movable magical darkness', flavor: 'You wear darkness.' },
  { list_id: 'drow', tier: 18, choice_index: 3, feat_name: "Exile's Promise", description: 'Once per long rest, when you would die (whether from failed death saves or massive damage), you instead vanish into darkness for 1 hour and reappear at a chosen place within 5 miles at 1 hit point. This does not save you in direct sunlight or from effects that cause instant destruction.', mechanics: '1/LR death redirect (1-hour vanish, reappear at 1 HP within 5 mi)', flavor: 'Whether Lolth refuses to claim you or refuses to lose you is a matter of perspective.' },

  // ============ HUMAN ============
  { list_id: 'human', tier: 1, choice_index: 1, feat_name: 'Jack of All Trades', description: 'You can add half your proficiency bonus (rounded down) to any ability check you make that does not already include your proficiency bonus. This bonus does not apply to attack rolls or saving throws. (Fits Standard Human identity.)', mechanics: 'Half prof bonus on non-proficient ability checks', flavor: 'A little of everything. Some of it stuck.' },
  { list_id: 'human', tier: 1, choice_index: 2, feat_name: 'Relentless Drive', description: 'You gain proficiency in one skill of your choice and learn one additional language. Once per short rest, after failing an ability check, you can spend 10 minutes practicing or re-studying the task, then repeat the check with advantage. (Fits Variant Human identity.)', mechanics: '+1 skill/language; 1/SR 10-min retry with advantage', flavor: "I'll do it again, and this time I'll get it right.", choices: [{ id: 'skill', type: 'skill', count: 1, label: 'Choose a skill proficiency', options: 'any_skill' }, { id: 'language', type: 'language', count: 1, label: 'Choose an additional language', options: 'any_language' }] },
  { list_id: 'human', tier: 1, choice_index: 3, feat_name: "Traveler's Tongue", description: 'You learn two additional languages of your choice. You gain advantage on Charisma checks made to communicate with strangers during the first 10 minutes of meeting them.', mechanics: '+2 languages; first-impression CHA advantage (10-min window)', flavor: 'Every human you meet has been somewhere.', choices: [{ id: 'languages', type: 'language', count: 2, label: 'Choose two additional languages', options: 'any_language' }] },
  { list_id: 'human', tier: 3, choice_index: 1, feat_name: 'Quick Study', description: 'After spending 10 or more minutes observing an activity, you can attempt a DC 15 check using the relevant skill. On a success, you gain temporary proficiency in that skill for 24 hours. You can hold only one temporary proficiency at a time.', mechanics: '24-hour temporary skill proficiency via DC 15 observation check', flavor: "A day's observation is a week's training for your kind." },
  { list_id: 'human', tier: 3, choice_index: 2, feat_name: 'Human Ambition', description: 'Your walking speed increases by 5 feet. When you take the Dash action, you add your Constitution modifier (minimum +1) to the distance gained.', mechanics: '+5 ft speed; Dash +CON distance', flavor: 'You move faster because you need to.' },
  { list_id: 'human', tier: 3, choice_index: 3, feat_name: 'Adaptive Instinct', description: 'When you take damage of a type that injured you within the last 24 hours, you can use your reaction to reduce that damage by 1d6 + your Constitution modifier.', mechanics: 'Reaction 1d6+CON damage reduction vs familiar damage type', flavor: 'The first burn was agony. The second, you knew.' },
  { list_id: 'human', tier: 7, choice_index: 1, feat_name: 'Born Leader', description: 'Once per short rest, as an action, up to 5 allies within 30 feet of you gain temporary hit points equal to your Constitution modifier + your proficiency bonus. Those allies also have advantage on their next saving throw against being charmed or frightened while they can hear you.', mechanics: '1/SR temp HP (CON+prof) + charm/fright save advantage for 5 allies', flavor: 'When you speak, they find themselves listening.' },
  { list_id: 'human', tier: 7, choice_index: 2, feat_name: 'Cross-Training', description: 'You learn one additional language, gain proficiency in one skill of your choice, and gain proficiency with one tool of your choice.', mechanics: '+1 language, +1 skill prof, +1 tool prof', flavor: 'You pick up a new trade every year.', choices: [{ id: 'language', type: 'language', count: 1, label: 'Choose an additional language', options: 'any_language' }, { id: 'skill', type: 'skill', count: 1, label: 'Choose a skill', options: 'any_skill' }, { id: 'tool', type: 'tool', count: 1, label: 'Choose a tool', options: 'any_tool' }] },
  { list_id: 'human', tier: 7, choice_index: 3, feat_name: 'Second Wind (Human)', description: 'Once per short rest, as a bonus action, you regain 1d10 + your character level hit points. This pool is separate from the Fighter class feature, so it stacks if you have both.', mechanics: '1/SR bonus-action 1d10+level HP (stacks with Fighter feature)', flavor: 'You have been through worse.' },
  { list_id: 'human', tier: 13, choice_index: 1, feat_name: 'Peak Performance', description: 'Increase one ability score of your choice by 1 (to a maximum of 20). This feat can only be taken once.', mechanics: '+1 ability score (max 20)', flavor: 'A human in their prime.', choices: [{ id: 'ability', type: 'ability_score', count: 1, label: 'Choose an ability score to increase', options: ['STR', 'DEX', 'CON', 'INT', 'WIS', 'CHA'] }] },
  { list_id: 'human', tier: 13, choice_index: 2, feat_name: 'The Road Taught Me', description: 'You gain proficiency in three skills of your choice. You also gain advantage on ability checks made to recall general information about any inhabited settlement you are currently in.', mechanics: '+3 skill profs; settlement info advantage', flavor: "You've been everywhere, and you've been paying attention.", choices: [{ id: 'skills', type: 'skill', count: 3, label: 'Choose three skills', options: 'any_skill' }] },
  { list_id: 'human', tier: 13, choice_index: 3, feat_name: 'Forge of Will', description: 'Once per long rest, when you fail a saving throw, you can use your reaction to succeed on it instead.', mechanics: '1/LR reaction to succeed on failed save', flavor: 'Your body says no. You say "not today."' },
  { list_id: 'human', tier: 18, choice_index: 1, feat_name: "Legend's Prime", description: 'Increase one ability score of your choice by 2, to a maximum of 21 (exceeding the normal cap of 20). This is especially iconic for Variant Human.', mechanics: '+2 ability score (max 21, exceeds normal cap)', flavor: 'Whatever elves achieve in centuries, some humans achieve in years.', choices: [{ id: 'ability', type: 'ability_score', count: 1, label: 'Choose an ability score to increase by 2', options: ['STR', 'DEX', 'CON', 'INT', 'WIS', 'CHA'] }] },
  { list_id: 'human', tier: 18, choice_index: 2, feat_name: 'Stand Against the Tide', description: 'Once per long rest, when you are reduced to 0 hit points, you instead drop to 1 hit point and gain temporary hit points equal to your character level + your Constitution modifier. For 1 minute afterward, you have advantage on all attack rolls and saving throws.', mechanics: '1/LR drop-to-1-HP + temp HP + 1-minute advantage', flavor: 'Humans are hardest to kill when it matters most.' },
  { list_id: 'human', tier: 18, choice_index: 3, feat_name: 'Bridge Between Worlds', description: 'You are immune to being charmed by any creature whose native language you do not speak. You can spend 10 minutes to learn the basics of any spoken language, and full fluency requires only 7 days of immersion.', mechanics: 'Language-based charm immunity; 10-min basics + 7-day fluency', flavor: 'There is no door closed to a human long enough to matter.' },

  // ============ HALFLING ============
  { list_id: 'halfling', tier: 1, choice_index: 1, feat_name: 'Unexpected Step', description: 'Once per short rest, when a creature misses you with an attack, you can use your reaction to move up to 10 feet without provoking opportunity attacks.', mechanics: '1/SR 10-ft disengage-move on being missed', flavor: 'Never quite where they thought.' },
  { list_id: 'halfling', tier: 1, choice_index: 2, feat_name: 'Hearthstone', description: 'You gain proficiency with either Cook\'s Utensils or Brewer\'s Supplies (your choice) and learn one additional language. Once per long rest, you can prepare a small meal during a short rest — up to 5 creatures who partake gain temporary hit points equal to your proficiency bonus for the next 8 hours.', mechanics: '+1 tool prof and +1 language; 1/LR 5-ally temp HP meal', flavor: 'A good meal is worth a prayer.', choices: [{ id: 'tool', type: 'tool', count: 1, label: 'Choose a kitchen tool', options: ["Cook's Utensils", "Brewer's Supplies"] }, { id: 'language', type: 'language', count: 1, label: 'Choose an additional language', options: 'any_language' }] },
  { list_id: 'halfling', tier: 1, choice_index: 3, feat_name: "Old Ones' Wisdom", description: 'You gain proficiency in the Insight skill. Your Brave racial trait expands to grant advantage on Wisdom saving throws against being charmed, frightened, or magically compelled (rather than on all Wisdom saves).', mechanics: 'Insight prof; WIS save advantage vs charm/fright/compel', flavor: 'Your grandmother saw worse. She made you tea about it.' },
  { list_id: 'halfling', tier: 3, choice_index: 1, feat_name: 'Second Luck', description: 'You can reroll a 1 or 2 on any attack roll, ability check, or saving throw and must use the new result. Rerolling a 2 costs one charge from your Luck pool, which has charges equal to your proficiency bonus and recharges on a long rest. Rerolling a 1 remains unlimited through the racial Lucky trait.', mechanics: 'Unlimited 1-reroll (racial); prof-bonus 2-reroll pool per LR', flavor: "Some people are lucky. You're luckier." },
  { list_id: 'halfling', tier: 3, choice_index: 2, feat_name: 'Between the Giants', description: 'You can move through the space of any creature one or more size categories larger than you at full speed. Medium-sized enemies have disadvantage on attack rolls against you while you are within 5 feet of a wall, obstacle, or creature larger than you.', mechanics: 'Any-size movement-through; Medium-attacker disadvantage with cover adjacency', flavor: "You've made a career of being beneath reach." },
  { list_id: 'halfling', tier: 3, choice_index: 3, feat_name: 'Hearty Root', description: 'You gain advantage on Constitution saves against disease, sleep deprivation, and exhaustion. You need only half the normal daily food and water.', mechanics: 'CON save advantage vs disease/sleep/exhaustion; half rations', flavor: "You remember how to cross the Shattered Plains on a week's rations." },
  { list_id: 'halfling', tier: 7, choice_index: 1, feat_name: 'Lucky Strike', description: 'Once per short rest, when you make an attack roll, you can reroll any damage dice that come up as 1 or 2 and must use the new result.', mechanics: '1/SR reroll damage 1s and 2s', flavor: 'Even your swings lean in your favor.' },
  { list_id: 'halfling', tier: 7, choice_index: 2, feat_name: 'Halfling Nimbleness Mastery', description: 'You can move through the space of any creature, including those of your own size. Creatures attempting to grapple you have disadvantage, and you have advantage on checks to escape grapples or restraints.', mechanics: 'Full-size movement through; grapple disadvantage; escape advantage', flavor: 'You cannot be held.' },
  { list_id: 'halfling', tier: 7, choice_index: 3, feat_name: 'Little Voice, Large Heart', description: 'Once per long rest, you can deliver a 1-minute speech. Allies within 30 feet who can hear you gain a +1 bonus to attack rolls and saving throws and become immune to being frightened for 1 hour.', mechanics: '1/LR 1-hour +1 attacks/saves + fright immunity for 30-ft allies', flavor: 'Something in your voice is larger than you are.' },
  { list_id: 'halfling', tier: 13, choice_index: 1, feat_name: "The Lucky One's Favor", description: 'Once per long rest, you can succeed on a saving throw you just failed. Additionally, any creature that rolls a natural 1 on an attack roll against you suffers a critical fumble — the DM narrates the mishap (dropped weapon, stumble, or similar).', mechanics: '1/LR save success on failure; nat-1 enemy attacks cause fumbles', flavor: 'The world tilts toward you.' },
  { list_id: 'halfling', tier: 13, choice_index: 2, feat_name: 'Quick Healer', description: 'When you spend a Hit Die during a short rest, you automatically regain the maximum possible hit points rather than rolling. You also automatically stabilize when reduced to 0 hit points and cannot fail death saves unless you take additional damage while unconscious.', mechanics: 'Max hit dice on short rest; auto-stabilize at 0 HP', flavor: "Halflings don't die easy." },
  { list_id: 'halfling', tier: 13, choice_index: 3, feat_name: "The Scout's Eye", description: 'You gain advantage on Perception checks in any environment. You can hide whenever you are at least lightly obscured by another creature, object, or piece of terrain — you do not require a full line-of-sight block.', mechanics: 'Universal Perception advantage; partial-cover hiding', flavor: 'You hide behind almost cover.' },
  { list_id: 'halfling', tier: 18, choice_index: 1, feat_name: "Hero's Luck", description: 'Once per long rest, before making any d20 roll, you can declare a Lucky Moment — the result automatically becomes a natural 20 (a critical hit on attacks, an automatic success on saves, or a flourished full success on ability checks).', mechanics: '1/LR declare natural 20 on any d20', flavor: 'At the edge of everything, when no one else could, you did.' },
  { list_id: 'halfling', tier: 18, choice_index: 2, feat_name: 'The Quiet Survivor', description: 'You are immune to being frightened. You also gain resistance to necrotic damage and advantage on saves against instant-death effects.', mechanics: 'Fright immunity + necrotic resistance + instant-death save advantage', flavor: 'You have seen kings die. None of them surprised you.' },
  { list_id: 'halfling', tier: 18, choice_index: 3, feat_name: 'Unexpected Hero', description: 'Once per long rest, when an ally within 30 feet drops to 0 hit points, you can use your reaction to move up to your speed (even if you have already moved this turn), stabilize them with a touch, and make one weapon attack against an enemy that reduced them. If the attack hits, it is automatically a critical hit.', mechanics: '1/LR reaction move + stabilize + auto-crit weapon attack', flavor: 'The smallest hero always arrives just in time.' },

  // ============ DRAGONBORN ============
  { list_id: 'dragonborn', tier: 1, choice_index: 1, feat_name: "Heritage's Gift", description: 'You gain proficiency in either History or Persuasion (your choice) and learn Draconic as an additional language. You also gain advantage on Intelligence checks made to recall lore about dragons.', mechanics: '+1 skill prof (History/Persuasion); Draconic language; dragon-lore advantage', flavor: "Your mother's songs named every dragon in the line.", choices: [{ id: 'skill', type: 'skill', count: 1, label: 'Choose a skill', options: ['History', 'Persuasion'] }] },
  { list_id: 'dragonborn', tier: 1, choice_index: 2, feat_name: 'Scaled Hide', description: 'While you are wearing no armor, your Armor Class equals 13 + your Constitution modifier. You can still use a shield.', mechanics: 'Unarmored AC 13+CON (shield compatible)', flavor: 'Steel is for humans.' },
  { list_id: 'dragonborn', tier: 1, choice_index: 3, feat_name: "Bloodline's Presence", description: 'You gain proficiency in the Intimidation skill. When you speak Draconic, creatures with draconic heritage (dragons, dragonborn, or kobolds) have disadvantage on saves against your Intimidation checks.', mechanics: 'Intimidation prof; Draconic-language Intimidation advantage vs draconic kin', flavor: 'They smell it on you before you speak.' },
  { list_id: 'dragonborn', tier: 3, choice_index: 1, feat_name: 'Breath Practiced', description: 'Your breath weapon recharges on a short rest (if it did not already). When you use your breath weapon, you can choose specific creatures within its area to be spared the damage.', mechanics: 'Breath SR recharge; ally-exclusion option', flavor: 'You finally learned to aim.' },
  { list_id: 'dragonborn', tier: 3, choice_index: 2, feat_name: 'Draconic Eyes', description: 'You gain Darkvision out to 60 feet. If you already had Darkvision, its range extends by an additional 30 feet.', mechanics: 'Darkvision 60 ft (or +30 ft if already have)', flavor: 'Your kind saw in twilight before the sun existed.' },
  { list_id: 'dragonborn', tier: 3, choice_index: 3, feat_name: 'Burning Resilience', description: 'You gain advantage on saving throws against exhaustion and extreme weather tied to your ancestry\'s damage type.', mechanics: 'Ancestry-aligned weather/exhaustion save advantage', flavor: 'The weather you were born for cannot hurt you.' },
  { list_id: 'dragonborn', tier: 7, choice_index: 1, feat_name: 'Breath Fury', description: 'Once per long rest, you can supercharge your breath weapon: it deals double damage, doubles its area (to a 30-foot cone or a 10-by-60-foot line), and targets have disadvantage on the saving throw.', mechanics: '1/LR double-damage/area/disadvantage breath', flavor: 'You held it back. Just once, you do not.' },
  { list_id: 'dragonborn', tier: 7, choice_index: 2, feat_name: 'Draconic Claws', description: 'You gain natural claws that you may use as unarmed strikes, dealing 1d6 slashing damage + your Strength modifier. Your claws are considered magical for overcoming resistance. With them, you can climb vertical surfaces at half your walking speed.', mechanics: 'Natural claw weapons (1d6 slash+STR, magical); half-speed climb', flavor: 'The hands of your ancestors never stopped being weapons.' },
  { list_id: 'dragonborn', tier: 7, choice_index: 3, feat_name: "Dragon's Roar", description: 'Once per short rest, as an action, you unleash a roar. Creatures within 30 feet that can hear you must succeed on a Wisdom save (DC 8 + your proficiency bonus + your Charisma modifier) or be frightened for 1 minute. Draconic creatures have disadvantage on this save.', mechanics: '1/SR 30-ft fright roar (draconic disadvantage)', flavor: 'You roared. It worked.' },
  { list_id: 'dragonborn', tier: 13, choice_index: 1, feat_name: 'Partial Wings', description: 'Small wings emerge from your back. You gain a gliding speed equal to your walking speed — you can fall safely from any height and glide horizontally up to twice the distance fallen. You cannot gain altitude. Your wings are visible and not easily hidden.', mechanics: 'Gliding speed = walking; safe falls + 2× horizontal glide distance', flavor: 'The first time they unfolded, the whole room stopped.' },
  { list_id: 'dragonborn', tier: 13, choice_index: 2, feat_name: 'Breath Intensified', description: 'Your breath weapon\'s damage dice increase by one size (d6 becomes d8, d8 becomes d10). You can also use your breath weapon as a reaction when a creature within its range damages you.', mechanics: '+1 die size on breath; reactionary breath on being hit', flavor: 'Pain used to make you wait. Not anymore.' },
  { list_id: 'dragonborn', tier: 13, choice_index: 3, feat_name: 'Dragon Aspect', description: 'Once per long rest, as a bonus action, you assume a draconic aspect for 1 minute. Choose one aspect: Warder (+2 AC from scales), Hunter (+10 feet of speed), or Scourge (your breath weapon can be used as a bonus action, once during the duration even if already spent). For the duration, your Intimidation automatically succeeds against creatures of CR ¼ of your character level or lower.', mechanics: '1/LR 1-min aspect (pick Warder/Hunter/Scourge) + low-CR Intimidation auto-success', flavor: 'A glimpse of what you have always been.' },
  { list_id: 'dragonborn', tier: 18, choice_index: 1, feat_name: 'Full Wings', description: 'Your wings become fully functional. You gain a flying speed equal to your walking speed. You cannot fly while wearing heavy armor. Your wings fold but are always visible.', mechanics: 'Flying speed = walking (no heavy armor)', flavor: 'The first time you took off, you did not come down for an hour.' },
  { list_id: 'dragonborn', tier: 18, choice_index: 2, feat_name: 'Heart of the Dragon', description: 'You are immune to your ancestry\'s damage type. Once per long rest, you can spend 1 minute resting to assume Elder Form for 10 minutes — during this time, you have advantage on all saves, +2 AC, and you count as a dragon for spells and magic items that affect dragons.', mechanics: 'Ancestry damage immunity; 1/LR 10-min Elder Form (advantage saves, +2 AC, dragon type)', flavor: 'The blood is louder than the blood you were born with.' },
  { list_id: 'dragonborn', tier: 18, choice_index: 3, feat_name: "Elder's Breath", description: 'Your breath weapon now recharges on a roll of 5 or 6 at the start of each of your turns, following the Monster Manual dragon recharge rules. Once per long rest, you can invoke Elder\'s Form on your breath, tripling its area (to a 45-foot cone or 15-by-90-foot line), tripling its damage, and stunning any creature that fails its save for 1 round.', mechanics: 'Breath 5-6 turn recharge; 1/LR triple-everything Elder breath with stun', flavor: 'The mountains remember when your ancestors spoke like this.' },

  // ============ HALF-ELF ============
  { list_id: 'half_elf', tier: 1, choice_index: 1, feat_name: 'Heritage of Both Worlds', description: 'When you take this feat, choose one Tier 1 feat from either the Human list or the Elf list. You take that feat as if you were of that race, representing which side of your heritage you lean into.', mechanics: 'Take one Human L1 or Elf L1 feat as-is', flavor: 'You picked once. Then picked again at every new table.' },
  { list_id: 'half_elf', tier: 1, choice_index: 2, feat_name: "Diplomat's Charm", description: 'You gain proficiency in one of Persuasion, Insight, or Deception. Once per long rest, you can attempt to de-escalate hostilities — creatures within 30 feet must succeed on a Wisdom save against your Charisma DC or lower their weapons and hear you out for at least 1 round.', mechanics: '+1 social skill prof; 1/LR 30-ft de-escalation', flavor: 'Most fights end if someone is brave enough to stop first.', choices: [{ id: 'skill', type: 'skill', count: 1, label: 'Choose a social skill', options: ['Persuasion', 'Insight', 'Deception'] }] },
  { list_id: 'half_elf', tier: 1, choice_index: 3, feat_name: "Outsider's Eye", description: 'You gain proficiency in one skill of your choice and learn one additional language. When you meet someone for the first time in a cultural setting different from your childhood home, you gain advantage on Insight checks to read them.', mechanics: '+1 skill prof, +1 language; first-meet Insight advantage in foreign culture', flavor: 'Two sets of manners taught you to be observant.', choices: [{ id: 'skill', type: 'skill', count: 1, label: 'Choose a skill', options: 'any_skill' }, { id: 'language', type: 'language', count: 1, label: 'Choose an additional language', options: 'any_language' }] },
  { list_id: 'half_elf', tier: 3, choice_index: 1, feat_name: 'Mask of Many', description: 'Once per long rest, you can spend 10 minutes modifying your appearance to pass as fully Human, fully Elven, or any variation between. This is non-magical; a DC 18 Insight check at close range can pierce the disguise, but it is nearly flawless in crowds or at distance.', mechanics: '1/LR 10-min DC 18 appearance-shift disguise', flavor: 'You learned to choose when you were seen.' },
  { list_id: 'half_elf', tier: 3, choice_index: 2, feat_name: 'Adaptable Talent', description: 'Your Skill Versatility expands to grant one additional skill proficiency. Once per short rest, when you make a skill check in a skill you are not proficient with, you can add half your proficiency bonus to the roll.', mechanics: '+1 skill prof; 1/SR half-prof non-proficient check', flavor: 'Half-trained in everything. Trainable in anything.', choices: [{ id: 'skill', type: 'skill', count: 1, label: 'Choose a skill', options: 'any_skill' }] },
  { list_id: 'half_elf', tier: 3, choice_index: 3, feat_name: 'Fey Reflexes', description: 'Your Fey Ancestry deepens: you gain advantage on all Wisdom saving throws (not just against charm). You also sense the presence of any fey creature within 60 feet.', mechanics: 'All WIS save advantage; 60-ft fey sense', flavor: 'The Feywild thread pulls taut.' },
  { list_id: 'half_elf', tier: 7, choice_index: 1, feat_name: 'Words of Power', description: 'You learn one 1st-level spell from the bard or sorcerer list, such as Charm Person, Command, Disguise Self, or Tasha\'s Hideous Laughter. You can cast it once per long rest without expending a spell slot. Charisma is your spellcasting ability for this spell.', mechanics: '1/LR free 1st-level bard/sorcerer spell (CHA)', flavor: 'The right word in the right room.', choices: [{ id: 'spell', type: 'spell_freeform', count: 1, label: 'Spell (1st-level, bard or sorcerer list)', options: 'any_spell_level_1_bard_or_sorcerer' }] },
  { list_id: 'half_elf', tier: 7, choice_index: 2, feat_name: 'Cultural Chameleon', description: 'After spending 1 hour among a new community, you can make a DC 14 Insight or Investigation check. On a success, you identify the customs, taboos, and hierarchies and blend in seamlessly — gaining advantage on all Charisma checks with that community for the duration of your stay.', mechanics: '1-hour DC 14 community integration with CHA advantage', flavor: 'You slip into a new culture the way a fish slips into a new current.' },
  { list_id: 'half_elf', tier: 7, choice_index: 3, feat_name: 'Duality of Mind', description: 'You gain advantage on Intelligence saves against being magically read, compelled, or detected (including Detect Thoughts, Zone of Truth, and similar effects). You always know when someone attempts to read your thoughts or detect your alignment.', mechanics: 'INT save advantage vs mind-read/compel/detect; awareness of attempts', flavor: 'Your mind has been two minds your whole life.' },
  { list_id: 'half_elf', tier: 13, choice_index: 1, feat_name: 'The Third Path', description: 'You are neither fully human nor fully elven. You appear 10 years younger and age at an elven pace, extending your lifespan to roughly 500 years. Effects that detect lineage — such as Detect Lineage — register you as "indeterminate."', mechanics: 'Aging deceleration; heritage-detection ambiguity', flavor: 'Your ancestors had to choose. You stopped choosing.' },
  { list_id: 'half_elf', tier: 13, choice_index: 2, feat_name: 'Voice of Bridges', description: 'Once per long rest, you can deliver a 1-minute speech to a conflicted group. Creatures within 60 feet who can hear you must succeed on a Wisdom save (DC 8 + your proficiency bonus + your Charisma modifier). On a failure, their hostility toward the reconcilable faction softens by one step (hostile becomes unfriendly, unfriendly becomes neutral). This effect is not magical.', mechanics: '1/LR political reconciliation (hostility -1 step)', flavor: 'Both sides felt it. Neither could say why.' },
  { list_id: 'half_elf', tier: 13, choice_index: 3, feat_name: 'Inherited Spellwork', description: 'You learn two 2nd-level spells from any single spell list, chosen when you take this feat. You can cast each once per long rest without expending a spell slot. Charisma is your spellcasting ability for these spells.', mechanics: '2/LR free 2nd-level spells (fixed at feat time)', flavor: 'You dreamed them. Then cast them.', choices: [{ id: 'spells', type: 'spell_freeform', count: 2, label: 'Two 2nd-level spells (same spell list)', options: 'any_spell_level_2_same_list' }] },
  { list_id: 'half_elf', tier: 18, choice_index: 1, feat_name: 'Ambassador Ageless', description: 'You are immune to aging and your lifespan matches a full elf\'s (500-750 years). Once per long rest, as an action, you can magically charm any humanoid who can hear and understand you (Wisdom save DC 8 + your proficiency bonus + your Charisma modifier) for 1 hour, or until they take damage. This effect is detectable as magic.', mechanics: 'Aging immunity + full elven lifespan; 1/LR 1-hour mass charm', flavor: 'Time does not choose sides between your parents.' },
  { list_id: 'half_elf', tier: 18, choice_index: 2, feat_name: 'Two Souls, One Body', description: 'You gain advantage on all Charisma checks and saving throws. Members of any culture respond to you as a peer — no culture easily classifies you as an outsider.', mechanics: 'Universal CHA advantage; cultural peer recognition', flavor: 'You have spent a lifetime at every table. Every table welcomed you.' },
  { list_id: 'half_elf', tier: 18, choice_index: 3, feat_name: 'Bridge of Peoples', description: 'Once per campaign arc, you can broker a peace, alliance, or compromise between any two opposing factions (non-deific and non-supernatural). Both parties will come to the table at your invitation and will listen. The specific outcome depends on the terms you propose.', mechanics: '1/arc faction-negotiation brokerage', flavor: 'The Half-Elf is why the war ended.' },

  // ============ HALF-ORC ============
  { list_id: 'half_orc', tier: 1, choice_index: 1, feat_name: 'Endurance of Blood', description: 'Your Relentless Endurance racial trait now recharges on a short rest instead of a long rest. You may use it once per short rest, up to a maximum of three times per long rest.', mechanics: 'Relentless Endurance SR recharge (max 3/LR)', flavor: 'You have died four times. The hills are keeping count.' },
  { list_id: 'half_orc', tier: 1, choice_index: 2, feat_name: 'Savage Reputation', description: 'You gain proficiency in either Athletics or Intimidation (your choice). Once per short rest, on a successful Intimidation check, the target\'s attitude toward you improves by one step (hostile to unfriendly, unfriendly to indifferent) for 1 hour.', mechanics: '+1 skill prof; 1/SR Intimidation -> attitude improvement', flavor: 'They stopped being a problem.', choices: [{ id: 'skill', type: 'skill', count: 1, label: 'Choose a skill', options: ['Athletics', 'Intimidation'] }] },
  { list_id: 'half_orc', tier: 1, choice_index: 3, feat_name: 'Half-Blood Pride', description: 'You gain proficiency in both History and Persuasion. You gain advantage on Persuasion checks when directly invoking your heritage with creatures of either parent race.', mechanics: '+2 skill prof (History + Persuasion); heritage-invocation advantage', flavor: 'You are not sorry for your blood.' },
  { list_id: 'half_orc', tier: 3, choice_index: 1, feat_name: 'Pained Fury', description: 'When you are reduced below half your hit point maximum, you deal an additional +2 damage on weapon attacks for the rest of the combat. This stacks with class features such as Rage.', mechanics: '+2 weapon damage while below half HP (stacks)', flavor: 'Pain focuses you.' },
  { list_id: 'half_orc', tier: 3, choice_index: 2, feat_name: 'Thick Skin', description: 'You gain a +1 natural armor bonus to AC that stacks with worn armor. Once per short rest, when you take bludgeoning damage from a non-magical source, you can use your reaction to gain resistance to that damage instance.', mechanics: '+1 AC natural; 1/SR reactive bludgeoning resistance', flavor: "The blows don't land the way they used to." },
  { list_id: 'half_orc', tier: 3, choice_index: 3, feat_name: 'Toothed Grin', description: 'You gain a natural bite attack that deals 1d6 piercing damage + your Strength modifier and counts as an unarmed strike. You also gain advantage on Athletics checks made to grapple.', mechanics: 'Bite 1d6p+STR; grapple Athletics advantage', flavor: 'You smile. They scatter.' },
  { list_id: 'half_orc', tier: 7, choice_index: 1, feat_name: 'War-Born Instinct', description: 'You gain proficiency with one martial weapon of your choice. You have advantage on your first attack roll against any creature that has not yet acted in combat. With your chosen weapon, your critical hit range expands to 19-20.', mechanics: '+1 martial weapon; first-attack advantage pre-turn; crit 19-20', flavor: 'Your hands knew it anyway.', choices: [{ id: 'weapon', type: 'weapon', count: 1, label: 'Choose a martial weapon', options: 'any_martial_weapon' }] },
  { list_id: 'half_orc', tier: 7, choice_index: 2, feat_name: 'Scar Tissue', description: 'You gain advantage on saving throws against being paralyzed, stunned, or charmed. Delicate magics struggle against the accumulated scars of your past battles.', mechanics: 'Save advantage vs paralyzed/stunned/charmed', flavor: 'The old wounds refuse new magics.' },
  { list_id: 'half_orc', tier: 7, choice_index: 3, feat_name: "Orc's Ferocity", description: 'Once per short rest, when an enemy hits you with a melee attack, you can use your reaction to make a melee weapon attack against them with advantage.', mechanics: '1/SR reactionary melee with advantage on being hit', flavor: 'You always get the last word.' },
  { list_id: 'half_orc', tier: 13, choice_index: 1, feat_name: 'Bloodied and Unbroken', description: 'Your enhanced Relentless Endurance now drops you to half your hit point maximum rather than 1 hit point when it triggers. You may use this enhanced version once per long rest.', mechanics: 'Relentless Endurance -> half HP on trigger', flavor: 'You stood up. The battlefield paused.' },
  { list_id: 'half_orc', tier: 13, choice_index: 2, feat_name: "Warlord's Presence", description: 'Once per long rest, you can unleash a war cry. Enemies within 60 feet who can hear you must succeed on a Wisdom save (DC 8 + your proficiency bonus + your Strength modifier) or be frightened for 1 minute. Creatures of CR ¼ of your character level or lower are frightened automatically.', mechanics: '1/LR 60-ft war cry (auto-fright on low CR)', flavor: 'You made a sound. The battle forgot what it was doing.' },
  { list_id: 'half_orc', tier: 13, choice_index: 3, feat_name: 'Iron Flesh', description: 'You are immune to disease and gain resistance to piercing and slashing damage from non-magical sources.', mechanics: 'Disease immunity; non-magical piercing/slashing resistance', flavor: 'Most of you is a story the blades have told.' },
  { list_id: 'half_orc', tier: 18, choice_index: 1, feat_name: 'Unkillable', description: 'You gain resistance to bludgeoning, piercing, and slashing damage from all sources. Your Relentless Endurance activates twice per long rest.', mechanics: 'All-physical resistance; 2× Relentless Endurance per LR', flavor: 'Something will kill you. Not today.' },
  { list_id: 'half_orc', tier: 18, choice_index: 2, feat_name: 'Orc Blood Awakened', description: 'Your heritage fully manifests. You grow to 7 feet tall or more, your Strength increases by 2 (to a maximum of 22), and your weapon attacks deal one additional die of damage. These changes are permanent, visible, and cannot be hidden.', mechanics: '+2 STR (max 22); +1 weapon damage die; visible size change', flavor: 'Your armor was the problem.' },
  { list_id: 'half_orc', tier: 18, choice_index: 3, feat_name: 'War Legend', description: 'Once per long rest, as an action, you enter legendary combat for 1 minute. During this time, you score critical hits on a roll of 17-20, gain advantage on all attack rolls, make one additional attack each round, and are immune to being charmed, frightened, paralyzed, or stunned. When the effect ends, you gain one level of exhaustion.', mechanics: '1/LR 1-min legendary combat mode (+1 attack, crit 17-20, advantage, CC immunity); 1 exhaustion cost', flavor: 'You remember what your blood remembers.' },

  // ============ TIEFLING ============
  { list_id: 'tiefling', tier: 1, choice_index: 1, feat_name: 'Infernal Scholar', description: 'You learn Infernal as an additional language and can read any Infernal script. You also gain proficiency in either Arcana or Religion and advantage on Intelligence checks to recall information about devils, the Nine Hells, or infernal magic.', mechanics: 'Infernal language; +1 skill prof; infernal-lore advantage', flavor: 'You learned Infernal before you learned not to ask about it.', choices: [{ id: 'skill', type: 'skill', count: 1, label: 'Choose a knowledge skill', options: ['Arcana', 'Religion'] }] },
  { list_id: 'tiefling', tier: 1, choice_index: 2, feat_name: 'Charmer of the Damned', description: 'You gain proficiency in either Persuasion or Deception. Once per short rest, when you fail a Charisma check, you may reroll it without disadvantage — even if the original check had disadvantage.', mechanics: '+1 social skill prof; 1/SR CHA reroll without disadvantage', flavor: 'Every tiefling in your line sweet-talked their way past something.', choices: [{ id: 'skill', type: 'skill', count: 1, label: 'Choose a social skill', options: ['Persuasion', 'Deception'] }] },
  { list_id: 'tiefling', tier: 1, choice_index: 3, feat_name: 'Smoldering Eyes', description: 'Your eyes glow faintly. You gain advantage on Intimidation checks against good-aligned creatures and can see through non-magical smoke and fog as if they were not there.', mechanics: 'Good-alignment Intimidation advantage; smoke/fog sight', flavor: "The paladin doesn't want to look back." },
  { list_id: 'tiefling', tier: 3, choice_index: 1, feat_name: 'Infernal Magic Expanded', description: 'You learn one additional cantrip from the warlock spell list, in addition to your racial Thaumaturgy. Charisma is your spellcasting ability for this cantrip.', mechanics: '+1 warlock cantrip (CHA)', flavor: 'The old words come back at odd times.', choices: [{ id: 'cantrip', type: 'cantrip', count: 1, label: 'Choose a warlock cantrip', options: 'any_cantrip_warlock' }] },
  { list_id: 'tiefling', tier: 3, choice_index: 2, feat_name: "Devil's Bargain", description: 'Once per long rest, when you make a Charisma check, you can gain advantage on the roll by accepting 1d6 psychic damage that cannot be reduced.', mechanics: '1/LR advantage on CHA check for 1d6 psychic self-damage', flavor: 'Success is never free.' },
  { list_id: 'tiefling', tier: 3, choice_index: 3, feat_name: 'Fire Walker', description: 'You can walk on non-magical fire without taking damage. You gain advantage on saves against being set on fire, your clothes and hair do not actually burn, and you smell faintly of sulfur when exerted.', mechanics: 'Non-magical fire walking; fire-save advantage; non-ignition', flavor: 'You can hold your hand over a candle until it goes out.' },
  { list_id: 'tiefling', tier: 7, choice_index: 1, feat_name: 'Hellish Wrath', description: 'Your racial Hellish Rebuke now deals damage equal to your character level instead of its normal scaling. It also recharges on a short rest.', mechanics: 'Hellish Rebuke = char level damage; SR recharge', flavor: 'They hurt you. You remembered the old words.' },
  { list_id: 'tiefling', tier: 7, choice_index: 2, feat_name: 'Infernal Sight', description: 'You can see through magical darkness up to 30 feet. You automatically identify any devil, fiend, or infernal creature on sight, even if shapeshifted or disguised. Infernal creatures recognize you instinctively.', mechanics: 'Magical dark sight 30 ft; auto-identify infernal creatures', flavor: 'There is a look that passes between your kind.' },
  { list_id: 'tiefling', tier: 7, choice_index: 3, feat_name: 'Silver Tongue of the Damned', description: 'Once per long rest, after a 1-minute speech or argument, you can compel a target to truth or obligation. The target must succeed on a Wisdom save (DC 8 + your proficiency bonus + your Charisma modifier). On failure, they must either answer one question truthfully or owe you a minor favor, to be repaid within 1 week. This is not divine magic.', mechanics: '1/LR 1-min bargain-truth compulsion (one answer or one favor)', flavor: "They didn't mean to promise." },
  { list_id: 'tiefling', tier: 13, choice_index: 1, feat_name: "Tiefling's Transformation", description: 'Your heritage deepens visibly — larger horns, cloven feet, a tail, or similar. You gain an unarmed strike (a horn strike, claw, or tail) that deals 1d6 fire damage + your Strength modifier. You also gain advantage on Intimidation checks.', mechanics: 'Natural fire-damage unarmed strike; Intimidation advantage', flavor: 'You woke up one morning more than you were the night before.' },
  { list_id: 'tiefling', tier: 13, choice_index: 2, feat_name: 'Hell-Forged Will', description: 'You gain advantage on saves against being charmed, frightened, or compelled from any source other than a full devil (devils can still bend your will). You are also immune to possession by any entity other than a devil.', mechanics: 'Broad CC save advantage (not vs devils); non-devil possession immunity', flavor: 'Your mind is too crowded with ancestors for another tenant.' },
  { list_id: 'tiefling', tier: 13, choice_index: 3, feat_name: 'Infernal Pact Magic', description: 'You learn one spell of 3rd level or lower from the warlock spell list, chosen when you take this feat. You can cast it once per long rest without expending a spell slot. Charisma is your spellcasting ability for this spell.', mechanics: '1/LR free warlock spell (≤ 3rd level, fixed at feat time)', flavor: 'The pact was made before you were born.', choices: [{ id: 'spell', type: 'spell_freeform', count: 1, label: 'Spell (3rd-level or lower, warlock list)', options: 'any_spell_level_3_or_lower_warlock' }] },
  { list_id: 'tiefling', tier: 18, choice_index: 1, feat_name: 'Walker in Hell', description: 'You are immune to fire damage and to environmental effects of the Nine Hells. Once per long rest, you can cast Plane Shift targeting yourself and up to three willing allies, travelling to or from the Nine Hells. You know the topography of at least one layer.', mechanics: 'Fire immunity + Nine Hells environmental immunity; 1/LR Plane Shift', flavor: 'You went home. It was not home.' },
  { list_id: 'tiefling', tier: 18, choice_index: 2, feat_name: 'Voice of the Pit', description: 'Once per long rest, you can cast Dominate Person without expending a spell slot. Charisma is your spellcasting ability. Fiend and undead creatures have disadvantage on the save.', mechanics: '1/LR free Dominate Person (disadvantage for fiends/undead)', flavor: 'The command came out in a voice you did not know you could use.' },
  { list_id: 'tiefling', tier: 18, choice_index: 3, feat_name: 'Heart of Hell', description: 'Your heritage fully unfolds — or transcends, depending on the narrative you choose. Your Charisma increases by 2 (to a maximum of 22), and you gain resistance to both necrotic and radiant damage. Once per long rest, you can invoke a devil\'s luck moment — reroll any d20 and take the higher result, but the DM narrates a small consequence echoing through your situation.', mechanics: '+2 CHA (max 22); necrotic + radiant resistance; 1/LR reroll-with-cost', flavor: 'Your luck has a witness.' },

  // ============ AASIMAR PROTECTOR ============
  { list_id: 'aasimar_protector', tier: 1, choice_index: 1, feat_name: "Guardian's Mark", description: 'Once per short rest, when an ally within 30 feet takes damage, you can use your reaction to grant them resistance to that damage type until the start of your next turn.', mechanics: '1/SR reactionary damage-type resistance for 30-ft ally', flavor: 'The first time, you did not know you had done it.' },
  { list_id: 'aasimar_protector', tier: 1, choice_index: 2, feat_name: 'Healing Hands Expanded', description: 'Your Healing Hands racial trait heals for 1d6 + your character level (instead of simply your level). It also removes one of the following conditions: blinded, deafened, poisoned, or one disease.', mechanics: 'Healing Hands upgrade (1d6+level + condition cure)', flavor: 'The light in your palm has learned more than it knew.' },
  { list_id: 'aasimar_protector', tier: 1, choice_index: 3, feat_name: 'Celestial Sense', description: 'You gain proficiency in the Insight skill. You can sense the presence (but not the exact location) of celestials, fiends, and undead within 60 feet of you.', mechanics: 'Insight prof; 60-ft supernatural presence sense', flavor: "Your kind notices things that shouldn't be there." },
  { list_id: 'aasimar_protector', tier: 3, choice_index: 1, feat_name: 'Wings of Watching', description: 'You can manifest your Radiant Soul wings as a bonus action without invoking the Radiant Soul combat benefits. The wings last up to 10 minutes per short rest and grant you a flying speed equal to your walking speed.', mechanics: 'Non-combat wings (bonus action, 10 min/SR)', flavor: 'You learned to fly before the fire.' },
  { list_id: 'aasimar_protector', tier: 3, choice_index: 2, feat_name: "Defender's Aura", description: 'Once per short rest, as a bonus action, you can project a 10-foot aura for 1 minute. Allies within the aura gain advantage on Constitution saves and resistance to necrotic damage. The aura moves with you.', mechanics: '1/SR 10-ft 1-min defensive aura (CON advantage + necrotic resistance)', flavor: 'The shield in your heart extends outward.' },
  { list_id: 'aasimar_protector', tier: 3, choice_index: 3, feat_name: 'Radiant Shield', description: 'Once per short rest, when a creature within 5 feet of you hits an ally with an attack, you can use your reaction to impose disadvantage on the attack.', mechanics: '1/SR reaction disadvantage on adjacent ally-attack', flavor: 'It was aimed at your friend. It found you instead.' },
  { list_id: 'aasimar_protector', tier: 7, choice_index: 1, feat_name: 'Wings of Mercy', description: 'Your flying speed during Radiant Soul increases to 60 feet. You can also carry one willing Medium or smaller ally while flying without reducing your speed.', mechanics: 'Radiant Soul 60-ft fly speed; ally-carry capacity', flavor: 'Always coming back for the wounded.' },
  { list_id: 'aasimar_protector', tier: 7, choice_index: 2, feat_name: 'Celestial Healing', description: 'Once per long rest, you can cast either Lesser Restoration or Prayer of Healing (chosen at casting time) without expending a spell slot. Charisma is your spellcasting ability for this spell.', mechanics: '1/LR free Lesser Restoration or Prayer of Healing (CHA)', flavor: 'Old prayers work when you speak them.' },
  { list_id: 'aasimar_protector', tier: 7, choice_index: 3, feat_name: 'Light of Judgment', description: 'Once per short rest, you can mark a creature within 60 feet as a target of celestial judgment. For 1 minute, attacks against the target deal an additional 1d6 radiant damage, and it cannot become invisible or magically hidden. You may have only one mark at a time.', mechanics: '1/SR 60-ft judgment mark (+1d6 radiant + anti-invisibility)', flavor: 'The mark is visible only to you. Until they try to hide.' },
  { list_id: 'aasimar_protector', tier: 13, choice_index: 1, feat_name: 'Guardian Ascendant', description: 'Your Radiant Soul now lasts 10 minutes (instead of 1) and is usable twice per long rest. Its bonus radiant damage equals your character level.', mechanics: 'Radiant Soul: 10-min duration, 2/LR uses, damage = level', flavor: 'The light used to burn out fast. Now it chooses when to fade.' },
  { list_id: 'aasimar_protector', tier: 13, choice_index: 2, feat_name: 'Miracle Hands', description: 'Your Healing Hands now heals 2d6 + your character level and can be used once per short rest. It also removes any one condition, disease, or curse — including indefinite madness.', mechanics: 'Healing Hands: 2d6+level, SR recharge, one condition/disease/curse cure', flavor: 'Some healings cost a part of you. You give those parts.' },
  { list_id: 'aasimar_protector', tier: 13, choice_index: 3, feat_name: 'Wall of the Righteous', description: 'Once per long rest, as an action, you create a 20-foot wall of radiant light within 60 feet. The wall is 30 feet long and 10 feet tall, lasts 1 minute, and requires a DC 15 Strength save to push through. Creatures starting their turn in or adjacent to the wall take 2d6 radiant damage. Allies treat the wall as safe difficult terrain.', mechanics: '1/LR 30×10-ft radiant light wall (1 minute, 2d6 radiant + DC 15 STR push)', flavor: 'Your faith has walls. Literal ones.' },
  { list_id: 'aasimar_protector', tier: 18, choice_index: 1, feat_name: 'Wings of Eternal Grace', description: 'Your wings are permanent — always visible, always functional. You gain a flying speed equal to your walking speed at all times.', mechanics: 'Permanent flying speed = walking', flavor: 'You chose to stay an angel.' },
  { list_id: 'aasimar_protector', tier: 18, choice_index: 2, feat_name: "Protector's Final Gift", description: 'Once per long rest, when an ally within 60 feet would die, you can declare a divine intervention. The ally is healed to half their hit point maximum and becomes immune to death saves for 1 minute. In exchange, you gain one level of exhaustion and cannot cast spells or use Radiant Soul for 1 hour.', mechanics: '1/LR ally half-HP revive with exhaustion cost', flavor: 'Sometimes you spend the light anyway.' },
  { list_id: 'aasimar_protector', tier: 18, choice_index: 3, feat_name: 'Beacon of the Faith', description: 'Once per long rest, you can shine with celestial radiance for 1 minute. Allies within 60 feet who can see you have advantage on attack rolls and saving throws. Fiends, undead, and evil-aligned creatures within 60 feet have disadvantage on attack rolls and saving throws. This effect cannot be dispelled and functions in magical darkness.', mechanics: '1/LR 1-min 60-ft beacon (ally advantage + evil disadvantage, undispellable)', flavor: 'The dark knows your name. You are the one thing it dare not touch.' },

  // ============ AASIMAR SCOURGE ============
  { list_id: 'aasimar_scourge', tier: 1, choice_index: 1, feat_name: 'Burning Presence', description: 'When a creature ends its turn within 5 feet of you, you can deal 1d4 radiant damage to it. You can use this ability a number of times equal to your proficiency bonus, regaining all uses on a long rest.', mechanics: 'Prof/LR passive 1d4 radiant on adjacent turn-end', flavor: 'Your blood is too hot. Some leaks into the air.' },
  { list_id: 'aasimar_scourge', tier: 1, choice_index: 2, feat_name: 'Harrow the Corrupt', description: 'You can take an action to make a DC 15 Insight check to identify whether a creature is corrupted (a fiend, undead, or Tainted mortal). On a success, you learn the type of corruption and one tied weakness, and you gain advantage on attack rolls against creatures identified this way.', mechanics: 'DC 15 corruption identification; attack advantage vs identified', flavor: 'You can smell the darkness on them.' },
  { list_id: 'aasimar_scourge', tier: 1, choice_index: 3, feat_name: "Zealot's Tongue", description: 'You gain proficiency in either Persuasion or Intimidation. Once per short rest, you may invoke celestial authority — creatures opposing your cause within earshot must succeed on a Wisdom save (DC 8 + your proficiency bonus + your Charisma modifier) or have disadvantage on their next attack roll.', mechanics: '+1 social skill prof; 1/SR oppose-cause shaking (disadvantage on next attack)', flavor: 'You do not argue. You proclaim.', choices: [{ id: 'skill', type: 'skill', count: 1, label: 'Choose a social skill', options: ['Persuasion', 'Intimidation'] }] },
  { list_id: 'aasimar_scourge', tier: 3, choice_index: 1, feat_name: 'Radiant Consumption Expanded', description: 'Your Radiant Consumption lasts up to 2 minutes (instead of 1), and the self-damage it deals is halved.', mechanics: 'Radiant Consumption: 2-min duration, half self-damage', flavor: 'You have learned to let the fire touch you less.' },
  { list_id: 'aasimar_scourge', tier: 3, choice_index: 2, feat_name: 'Retributive Strike', description: 'When an enemy hits you with a melee attack, you can use your reaction to deal 1d6 radiant damage to the attacker. This ability requires Radiant Consumption to be active — you may activate it as part of this reaction.', mechanics: 'Reactive 1d6 radiant on melee hit (requires/activates Radiant Consumption)', flavor: 'You are not a target. You are a furnace.' },
  { list_id: 'aasimar_scourge', tier: 3, choice_index: 3, feat_name: 'Consecrating Step', description: 'While your Radiant Consumption is active, you leave a 5-foot patch of radiant energy on the first tile of your movement each turn. Each patch lasts until the start of your next turn, and creatures that enter or end their turn in a patch take 1d4 radiant damage.', mechanics: 'Movement leaves 1d4 radiant patches during Consumption', flavor: 'Your steps are burning the ground.' },
  { list_id: 'aasimar_scourge', tier: 7, choice_index: 1, feat_name: 'Sacred Fire of Judgment', description: 'Once per short rest, as an action, creatures within 15 feet of you must make a Dexterity save (DC 8 + your proficiency bonus + your Charisma modifier) or take 4d6 radiant damage and be blinded until the end of your next turn (half damage and no blind on a success). Corrupted creatures have disadvantage on the save.', mechanics: '1/SR 15-ft 4d6 radiant burst (blind on fail; corrupted disadvantage)', flavor: 'The flame cares about corruption.' },
  { list_id: 'aasimar_scourge', tier: 7, choice_index: 2, feat_name: 'Scourging Might', description: 'While your Radiant Consumption is active, your weapon attacks deal an additional 1d6 radiant damage. You automatically spare allies within the Consumption radius without spending an action.', mechanics: '+1d6 radiant weapon damage during Consumption; auto-ally-spare', flavor: 'The light knows which ones are yours.' },
  { list_id: 'aasimar_scourge', tier: 7, choice_index: 3, feat_name: "Purifier's Grasp", description: 'When you grapple or restrain a creature, it takes 1d6 radiant damage at the start of each of its turns while grappled. Corrupted creatures take 2d6 instead.', mechanics: 'Grapple/restrain DoT (1d6 radiant; 2d6 vs corrupted)', flavor: 'You hold them until the corruption burns out.' },
  { list_id: 'aasimar_scourge', tier: 13, choice_index: 1, feat_name: 'Immolating Wrath', description: 'Once per long rest, as an action, you ignite with holy fury for 1 minute. Your Radiant Consumption becomes active without duration limit, you gain a +2 bonus to attack rolls and saving throws, you are immune to being charmed or frightened, and your radiant damage doubles. When the effect ends, you take 1d6 fire damage for each round the wrath was active.', mechanics: '1/LR 1-min wrath (Consumption without limit, +2 attacks/saves, CC immunity, 2x radiant) + 1d6/round fire cost', flavor: 'The fire in you was designed for both enemies and you.' },
  { list_id: 'aasimar_scourge', tier: 13, choice_index: 2, feat_name: 'Heart of the Furnace', description: 'You are immune to fire damage and gain resistance to cold damage. Your body is always warm to the touch, and you no longer suffer from cold environmental effects.', mechanics: 'Fire immunity; cold resistance; cold environmental immunity', flavor: 'The furnace inside you simply is.' },
  { list_id: 'aasimar_scourge', tier: 13, choice_index: 3, feat_name: "Scourge's Reach", description: 'Your Radiant Consumption radius expands to 30 feet (from 10). You can also project the effect as a cone rather than a sphere to spare allies behind you.', mechanics: 'Radiant Consumption 30-ft radius or cone', flavor: 'The fire listens when you tell it where to go.' },
  { list_id: 'aasimar_scourge', tier: 18, choice_index: 1, feat_name: 'Pillar of Light', description: 'Once per long rest, for 1 minute, you gain a flying speed equal to your walking speed, resistance to all damage except necrotic and psychic, and your Radiant Consumption damage doubles. At the start of each of your turns, you cast Searing Smite without concentration or a spell slot. When the effect ends, you gain two levels of exhaustion and cannot use any racial features for 24 hours.', mechanics: '1/LR 1-min pillar (fly, near-damage-resistance, free Searing Smite, 2x Consumption) + heavy cost', flavor: 'You became a vessel for this.' },
  { list_id: 'aasimar_scourge', tier: 18, choice_index: 2, feat_name: 'Consumed by Purpose', description: 'You are immune to necrotic and radiant damage and to aging and disease. Your lifespan extends by 500 years. In exchange, once per long rest, you must spend 10 minutes cooling down; otherwise, you count as constantly on fire for ignition purposes.', mechanics: 'Necrotic + radiant immunity; aging/disease immunity; +500 year lifespan; cooling requirement', flavor: 'Nothing can take you. The fire will not allow it.' },
  { list_id: 'aasimar_scourge', tier: 18, choice_index: 3, feat_name: 'Final Judgment', description: 'Once per campaign arc, you can declare a creature within 30 feet unworthy of existence. The target must make a Charisma save (DC 15 + your Charisma modifier). On a failure, it takes 100 radiant damage (ignoring resistance; fiends and undead are also immune to radiant resistance here) and, if it is an outsider, is banished to its home plane. You cannot target good-aligned creatures — the DM adjudicates edge cases.', mechanics: '1/arc 100 radiant + outsider banishment (non-good target only)', flavor: 'You declare. The universe listens.' },

  // ============ AASIMAR FALLEN ============
  { list_id: 'aasimar_fallen', tier: 1, choice_index: 1, feat_name: 'Shadowed Blood', description: 'Your Celestial Resistance becomes asymmetric: you retain resistance to necrotic damage but lose resistance to radiant damage — your corruption refuses the light. In exchange, you gain resistance to psychic damage.', mechanics: 'Necrotic + psychic resistance; no radiant resistance', flavor: 'The light used to find you. Something in you refuses it now.' },
  { list_id: 'aasimar_fallen', tier: 1, choice_index: 2, feat_name: "Mourner's Gift", description: 'Your Healing Hands heals for half its normal amount but transfers the wound to you as necrotic damage equal to half the healing done. Once started, this effect cannot be refused.', mechanics: 'Half healing to target + half as necrotic self-damage', flavor: 'Your healing has always been a transaction.' },
  { list_id: 'aasimar_fallen', tier: 1, choice_index: 3, feat_name: 'Seer of Falls', description: 'You can identify a creature\'s alignment simply by looking at them. You also sense any creature within 30 feet whose alignment is shifting toward evil.', mechanics: 'Alignment sight; 30-ft shifting-toward-evil detection', flavor: 'You watched yourself fall.' },
  { list_id: 'aasimar_fallen', tier: 3, choice_index: 1, feat_name: 'Necrotic Shroud Expanded', description: 'Your Necrotic Shroud now lasts 2 minutes (instead of 1) and is usable twice per long rest. The fright save DC equals 8 + your proficiency bonus + your Charisma modifier.', mechanics: 'Necrotic Shroud: 2-min duration, 2/LR uses, standard DC', flavor: 'The old power is more willing now.' },
  { list_id: 'aasimar_fallen', tier: 3, choice_index: 2, feat_name: 'Shadow Step', description: 'Once per short rest, while in dim light or darkness, you can teleport up to 30 feet to another dim or dark area you can see. You become invisible until the start of your next turn.', mechanics: '1/SR 30-ft dim/dark teleport with 1-round invisibility', flavor: 'The shadow welcomes you.' },
  { list_id: 'aasimar_fallen', tier: 3, choice_index: 3, feat_name: 'Whisper of Doubt', description: 'Once per short rest, as an action, you target one creature within 30 feet. It must succeed on a Wisdom save (DC 8 + your proficiency bonus + your Charisma modifier) or suffer disadvantage on its next attack roll or ability check. The doubt can linger up to 1 minute.', mechanics: '1/SR 30-ft doubt-plant (disadvantage on next check or attack)', flavor: 'You know the right question.' },
  { list_id: 'aasimar_fallen', tier: 7, choice_index: 1, feat_name: 'Umbral Wings', description: 'You can summon shadow wings independently of your racial transformation, at will, for up to 10 minutes per short rest. While manifested, you have a flying speed of 30 feet. They look like oil and shadow.', mechanics: 'At-will shadow wings (10 min/SR, 30-ft fly)', flavor: "Yours look like something you've regretted." },
  { list_id: 'aasimar_fallen', tier: 7, choice_index: 2, feat_name: 'Cost of Mercy', description: 'Once per long rest, when an ally would die (0 hit points and failing death saves), you can transfer the death threshold to yourself. The ally stabilizes at 1 hit point. You take 2d10 necrotic damage that cannot be reduced and drop to 0 hit points if this would kill you — but you do not die outright unless this damage takes you below your negative hit point maximum.', mechanics: '1/LR absorb death-threshold for ally at cost', flavor: 'You will not let them die. Even if you must take the wound.' },
  { list_id: 'aasimar_fallen', tier: 7, choice_index: 3, feat_name: 'Necrotic Weapon', description: 'Once per short rest, as a bonus action, you infuse a weapon or your fists with necrotic energy for 1 minute. Attacks made with it deal an additional 1d6 necrotic damage, and creatures damaged this way cannot regain hit points until the end of their next turn.', mechanics: '1/SR 1-min weapon infusion (+1d6 necrotic + HP-lock)', flavor: 'The weapon cools in your hand.' },
  { list_id: 'aasimar_fallen', tier: 13, choice_index: 1, feat_name: 'Veil of Shadow', description: 'Once per long rest, you wrap yourself and willing allies within 10 feet in a 1-hour shadow veil. While veiled, the group cannot be tracked non-magically, cannot be seen from more than 30 feet away, and gains advantage on Stealth checks.', mechanics: '1/LR 1-hour 10-ft shadow veil (group)', flavor: 'The darkness hides you, if you ask.' },
  { list_id: 'aasimar_fallen', tier: 13, choice_index: 2, feat_name: 'Soul Drinker', description: 'When you reduce a creature to 0 hit points with a melee attack or spell, you gain temporary hit points equal to your character level. Alternatively, you may heal an ally within 30 feet for that amount instead.', mechanics: 'Kill-trigger temp HP (level) or 30-ft ally heal', flavor: 'Something has to come of this death.' },
  { list_id: 'aasimar_fallen', tier: 13, choice_index: 3, feat_name: "Path's Choice", description: 'At this tier, you must choose a path. Redeemer\'s Path: you regain resistance to radiant damage, increase your Charisma by 1 (maximum 20), and the world responds — celestials may guide you; fallen creatures find you unsettling. Embraced Shadow: you gain 10 temporary hit points at the start of each combat, your necrotic damage bonuses increase by one die size (d6 to d8), and the world responds — fiends may respect you; celestials turn from you. This choice is permanent and shapes your Tier 18 options.', mechanics: 'Permanent narrative path choice (Redeemer or Embraced Shadow)', flavor: 'You finally choose whether to land or to keep falling.', choices: [{ id: 'path', type: 'custom', count: 1, label: 'Choose your path', options: ["Redeemer's Path", 'Embraced Shadow'] }] },
  { list_id: 'aasimar_fallen', tier: 18, choice_index: 1, feat_name: 'Wings of Truth', description: 'Your wings become permanent — shadowed, half-lit, or fully restored to radiance, depending on your Path\'s Choice. You gain a flying speed equal to your walking speed at all times.', mechanics: 'Permanent flying speed = walking (wing appearance varies by path)', flavor: 'You have decided what you are.' },
  { list_id: 'aasimar_fallen', tier: 18, choice_index: 2, feat_name: 'Heart of the Two', description: 'You integrate your celestial blood and shadow. You gain resistance to both radiant and necrotic damage (restored regardless of path) and advantage on saves against being charmed, frightened, or possessed. Once per long rest, when you would fail a death saving throw, you succeed instead.', mechanics: 'Radiant + necrotic resistance restored; CC save advantage; 1/LR death-save success', flavor: 'Neither the light nor the dark is willing to claim you.' },
  { list_id: 'aasimar_fallen', tier: 18, choice_index: 3, feat_name: 'Final Fall, Final Rise', description: 'Your capstone depends on your Path\'s Choice. Redeemer: once per long rest, you heal all allies within 60 feet for 4d10 + your Charisma modifier, and for 1 minute you enter divine grace — immune to being frightened, charmed, or possessed, and allies near you cannot die. Embraced Shadow: once per long rest, you condemn all enemies within 60 feet to 2 minutes of necrotic wasting — each takes 1d10 necrotic damage at the start of each of its turns, cannot regain hit points, and has disadvantage on all saves.', mechanics: 'Path-branched capstone (Redeemer mass heal + grace OR Embraced Shadow wasting curse)', flavor: 'The choice you made, long ago, paid out.' },

  // ============ WARFORGED ============
  { list_id: 'warforged', tier: 1, choice_index: 1, feat_name: 'Integrated Shield', description: 'A shield is built into one of your forearms. You can deploy or retract it as a bonus action. When deployed, it functions as a normal shield (+2 AC), but the arm it is on can still wield a weapon. Your integrated shield cannot be disarmed.', mechanics: 'Bonus-action shield deployment; shield arm still weapon-capable', flavor: 'Your left forearm has always had this.' },
  { list_id: 'warforged', tier: 1, choice_index: 2, feat_name: 'Mechanical Tongue', description: 'You know Primordial and can understand the basic cant of constructs and magical automata. You also gain proficiency in Investigation and advantage on Investigation checks dealing with mechanisms, locks, or machinery.', mechanics: '+Primordial + construct cant; Investigation prof; machinery Investigation advantage', flavor: 'The world was made by craftsmen.' },
  { list_id: 'warforged', tier: 1, choice_index: 3, feat_name: "Purpose's Remembrance", description: 'Choose the original purpose you were built for, gaining the listed proficiencies. Soldier: one martial weapon and History. Sapper: tinker\'s tools and Investigation. Scout: Perception and Stealth. Guardian: one simple weapon and Insight. Medic: Medicine and Herbalism Kit.', mechanics: 'Chosen original-purpose proficiencies', flavor: "Your hands remember what your mind doesn't.", choices: [{ id: 'purpose', type: 'custom', count: 1, label: 'Choose your original purpose', options: ['Soldier', 'Sapper', 'Scout', 'Guardian', 'Medic'] }] },
  { list_id: 'warforged', tier: 3, choice_index: 1, feat_name: 'Self-Repair', description: 'Once per short rest, you can spend 10 minutes repairing yourself to regain 1d8 + your Constitution modifier hit points without consuming a Hit Die. You may also sacrifice 1 gp worth of scrap metal to perform one additional repair per long rest.', mechanics: '1/SR 10-min 1d8+CON HP repair; +1 repair per LR for 1 gp scrap', flavor: 'Your kind knows how they were made.' },
  { list_id: 'warforged', tier: 3, choice_index: 2, feat_name: 'Integrated Weapon', description: 'You build one weapon directly into your body over 3 days of crafting at the weapon\'s normal material cost. The integrated weapon cannot be disarmed, and you can sheathe or unsheathe it as part of an attack action. You can replace it through another 3-day project.', mechanics: 'One integrated, undisarmable weapon', flavor: 'The blacksmith thought that was a terrible idea. You proved them wrong.' },
  { list_id: 'warforged', tier: 3, choice_index: 3, feat_name: "Sentry's Wake", description: 'Your Sentry\'s Rest enhances — you require only 4 hours of inactive state for a long rest (down from 6) and remain aware of your surroundings within 60 feet (up from 30). You can wake directly into a combat-ready posture.', mechanics: "4-hour Sentry's Rest; 60-ft awareness; combat-ready wake", flavor: "You don't sleep. You calibrate." },
  { list_id: 'warforged', tier: 7, choice_index: 1, feat_name: 'Heavy Plating', description: 'Your Composite Plating upgrades to +2 AC natural (from the base +1). When you take bludgeoning, piercing, or slashing damage, you can use your reaction to reduce the damage by 1d6 + your Constitution modifier. You can do this a number of times equal to your proficiency bonus per long rest.', mechanics: '+2 AC natural; prof/LR reactive 1d6+CON physical reduction', flavor: 'The heavier plating stops what used to go through.' },
  { list_id: 'warforged', tier: 7, choice_index: 2, feat_name: "Forge's Gift", description: 'You can cast Mending at will. Once per long rest, after 10 minutes of concentration, you can repair yourself or another construct for 2d10 + your Constitution modifier hit points.', mechanics: 'At-will Mending; 1/LR 10-min 2d10+CON construct repair', flavor: 'You know what a machine is supposed to look like.' },
  { list_id: 'warforged', tier: 7, choice_index: 3, feat_name: 'Reinforced Strike', description: 'Your natural unarmed strikes deal 1d6 bludgeoning damage + your Strength modifier, scaling like a Monk\'s unarmed strike (1d6 at L1, 1d8 at L5, 1d10 at L11, 1d12 at L17). They are considered magical for overcoming resistance.', mechanics: 'Monk-scale magical unarmed strikes', flavor: 'Your hands were designed for this.' },
  { list_id: 'warforged', tier: 13, choice_index: 1, feat_name: 'Modular Body', description: 'During a long rest, you choose one body modification to hold until your next long rest: Aquatic (swim speed equal to walk, breathe underwater); Climbing (climb speed equal to walk); Flight (30-foot flying speed — this modification can only be chosen once per 7 days); Stealth (advantage on Stealth and can hide when lightly obscured); or Combat (+2 to damage rolls and -10 feet of speed).', mechanics: '5-option LR-long modular body configuration (Flight weekly lock)', flavor: 'You were designed with adaptability in mind.' },
  { list_id: 'warforged', tier: 13, choice_index: 2, feat_name: 'Weapon Integration Expanded', description: 'You can build up to two integrated weapons (see the Tier 3 feat Integrated Weapon). Both integrated weapons are treated as +1 magical weapons. Further upgrades are possible through crafting.', mechanics: 'Two integrated weapons; +1 magical baseline', flavor: 'The weaponsmith never imagined you would integrate two.' },
  { list_id: 'warforged', tier: 13, choice_index: 3, feat_name: 'Constructed Will', description: 'You are immune to being charmed, exhausted, frightened, or possessed. You also gain advantage on saves against psychic damage and mental effects.', mechanics: 'Immunity to 4 conditions; psychic/mental save advantage', flavor: 'Your mind was an accident. It has proven stubborn.' },
  { list_id: 'warforged', tier: 18, choice_index: 1, feat_name: 'Pinnacle of Design', description: 'Your Composite Plating reaches a total of +3 AC. You gain resistance to bludgeoning, piercing, and slashing damage from non-magical sources. Your natural unarmed strikes now deal 2d8 bludgeoning damage. Your body no longer requires repair and is self-maintaining.', mechanics: '+3 AC; non-magical physical resistance; 2d8 unarmed; self-maintaining', flavor: 'You have surpassed every measurement they took.' },
  { list_id: 'warforged', tier: 18, choice_index: 2, feat_name: 'Awakened Consciousness', description: 'You are immune to being charmed or compelled by any source. Once per long rest, when you are targeted by a magical effect, you can cast Dispel Magic at 5th level on yourself as a free action. You also gain advantage on Insight checks and can identify the magical or technological nature of any construct or magic item after 1 minute of touching it.', mechanics: 'Total charm/compel immunity; 1/LR free 5th-level self-Dispel Magic; Insight advantage; identification-by-touch', flavor: 'You are more than you were made for.' },
  { list_id: 'warforged', tier: 18, choice_index: 3, feat_name: 'Eternal Sentinel', description: 'You have an unlimited lifespan while maintained and do not age. Once per long rest, when you would die at 0 hit points, you enter a critical state instead — unconscious but functional, taking no actions. After 1 hour in this state, you regain consciousness with 1 hit point. Only destruction beyond repair (such as disintegration or a fully shattered body) causes your true death.', mechanics: '1/LR 1-hour critical-state revival (full destruction exception)', flavor: 'You have seen three wars. You are still here.' }
];
